Prompt:
Build a cafeteria ordering website for university students with login, menu browsing, cart, and order tracking. Use React for frontend and Flask for backend.

TaskSpec:
{
  "app_name": "Campus Cafeteria Ordering System",
  "app_type": "web_app",
  "description": "A web application for university students to browse food items, add them to cart, place orders, and track their order status.",
  "target_users": [
    "students",
    "cafeteria_staff"
  ],
  "frontend": {
    "pages": [
      {
        "name": "Home",
        "route": "/",
        "components": [
          "Navbar",
          "HeroSection",
          "FeaturedMenu",
          "Footer"
        ]
      },
      {
        "name": "Menu",
        "route": "/menu",
        "components": [
          "Navbar",
          "FoodCardGrid",
          "CategoryFilter"
        ]
      },
      {
        "name": "Cart",
        "route": "/cart",
        "components": [
          "Navbar",
          "CartItemList",
          "OrderSummary"
        ]
      },
      {
        "name": "Orders",
        "route": "/orders",
        "components": [
          "Navbar",
          "OrderHistoryTable",
          "OrderStatusBadge"
        ]
      }
    ],
    "shared_components": [
      "Navbar",
      "Layout",
      "FoodCard"
    ],
    "features": [
      "menu browsing",
      "cart management",
      "order tracking"
    ]
  },
  "backend": {
    "endpoints": [
      {
        "method": "GET",
        "path": "/api/menu",
        "purpose": "Fetch all food items"
      },
      {
        "method": "GET",
        "path": "/api/orders",
        "purpose": "Fetch order history"
      }
    ]
  },
  "database": {
    "tables": [
      {
        "name": "menu_items",
        "columns": [
          "id",
          "name",
          "category",
          "price"
        ]
      },
      {
        "name": "orders",
        "columns": [
          "id",
          "item_count",
          "total_amount",
          "status"
        ]
      }
    ]
  },
  "auth_required": false
}

{"files": [{"path": "frontend/src/App.jsx", "content": "import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Menu from './pages/Menu';
import Cart from './pages/Cart';
import Orders from './pages/Orders';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/menu' element={<Menu />} />
        <Route path='/cart' element={<Cart />} />
        <Route path='/orders' element={<Orders />} />
      </Routes>
    </BrowserRouter>
  );
}"}, {"path": "frontend/src/components/Navbar.jsx", "content": "import React from 'react';
import { NavLink } from 'react-router-dom';

const linkStyle = ({ isActive }) => ({
  textDecoration: 'none',
  color: isActive ? '#0f172a' : '#475569',
  fontWeight: isActive ? '700' : '500'
});

export default function Navbar() {
  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#ffffff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h2 style={{ margin: 0 }}>Campus Cafeteria</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={linkStyle}>Home</NavLink>
          <NavLink to='/menu' style={linkStyle}>Menu</NavLink>
          <NavLink to='/cart' style={linkStyle}>Cart</NavLink>
          <NavLink to='/orders' style={linkStyle}>Orders</NavLink>
        </div>
      </div>
    </nav>
  );
}"}, {"path": "frontend/src/components/FoodCard.jsx", "content": "import React from 'react';

export default function FoodCard({ item }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '16px', background: '#fff', boxShadow: '0 2px 10px rgba(0,0,0,0.05)' }}>
      <h3 style={{ marginTop: 0 }}>{item.name}</h3>
      <p style={{ color: '#64748b' }}>Category: {item.category}</p>
      <p style={{ fontWeight: '700' }}>${item.price}</p>
      <button style={{ marginTop: '8px', padding: '10px 14px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff', cursor: 'pointer' }}>
        Add to Cart
      </button>
    </div>
  );
}"}, {"path": "frontend/src/pages/Home.jsx", "content": "import React from 'react';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ background: '#f8fafc', borderRadius: '18px', padding: '32px', border: '1px solid #e2e8f0' }}>
        <h1 style={{ marginTop: 0 }}>Order your campus meals easily</h1>
        <p style={{ fontSize: '16px', color: '#475569', maxWidth: '700px' }}>
          Browse food items, manage your cart, and track your orders from one simple student-friendly portal.
        </p>
        <div style={{ display: 'flex', gap: '12px', marginTop: '20px' }}>
          <a href='/menu' style={{ textDecoration: 'none', padding: '10px 16px', background: '#0f172a', color: '#fff', borderRadius: '10px' }}>Browse Menu</a>
          <a href='/orders' style={{ textDecoration: 'none', padding: '10px 16px', background: '#e2e8f0', color: '#0f172a', borderRadius: '10px' }}>Track Orders</a>
        </div>
      </div>
    </div>
  );
}"}, {"path": "frontend/src/pages/Menu.jsx", "content": "import React from 'react';
import FoodCard from '../components/FoodCard';

const items = [
  { id: 1, name: 'Burger', category: 'Fast Food', price: 10 },
  { id: 2, name: 'Fries', category: 'Sides', price: 5 },
  { id: 3, name: 'Pizza Slice', category: 'Fast Food', price: 8 },
  { id: 4, name: 'Juice', category: 'Drinks', price: 4 }
];

export default function Menu() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <div>
          <h1 style={{ marginBottom: '6px' }}>Menu</h1>
          <p style={{ color: '#64748b' }}>Explore available food items by category.</p>
        </div>
        <select style={{ padding: '10px 12px', borderRadius: '10px', border: '1px solid #cbd5e1' }}>
          <option>All Categories</option>
          <option>Fast Food</option>
          <option>Sides</option>
          <option>Drinks</option>
        </select>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(230px, 1fr))', gap: '18px' }}>
        {items.map(item => <FoodCard key={item.id} item={item} />)}
      </div>
    </div>
  );
}"}, {"path": "frontend/src/pages/Cart.jsx", "content": "import React from 'react';

const cartItems = [
  { id: 1, name: 'Burger', quantity: 1, price: 10 },
  { id: 2, name: 'Juice', quantity: 2, price: 4 }
];

export default function Cart() {
  const total = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Cart</h1>
      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '20px' }}>
        <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px' }}>
          {cartItems.map(item => (
            <div key={item.id} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 0', borderBottom: '1px solid #f1f5f9' }}>
              <div>
                <strong>{item.name}</strong>
                <p style={{ margin: '4px 0', color: '#64748b' }}>Quantity: {item.quantity}</p>
              </div>
              <span>${item.price * item.quantity}</span>
            </div>
          ))}
        </div>
        <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', height: 'fit-content' }}>
          <h3>Order Summary</h3>
          <p>Total: <strong>${total}</strong></p>
          <button style={{ width: '100%', padding: '12px', background: '#0f172a', color: '#fff', border: 'none', borderRadius: '10px' }}>
            Proceed to Checkout
          </button>
        </div>
      </div>
    </div>
  );
}"}, {"path": "frontend/src/pages/Orders.jsx", "content": "import React from 'react';

const orders = [
  { id: 101, item_count: 3, total: 22, status: 'Preparing' },
  { id: 102, item_count: 2, total: 14, status: 'Delivered' }
];

export default function Orders() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Orders</h1>
      <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f8fafc' }}>
            <tr>
              <th style={{ textAlign: 'left', padding: '14px' }}>Order ID</th>
              <th style={{ textAlign: 'left', padding: '14px' }}>Items</th>
              <th style={{ textAlign: 'left', padding: '14px' }}>Total</th>
              <th style={{ textAlign: 'left', padding: '14px' }}>Status</th>
            </tr>
          </thead>
          <tbody>
            {orders.map(order => (
              <tr key={order.id}>
                <td style={{ padding: '14px', borderTop: '1px solid #f1f5f9' }}>#{order.id}</td>
                <td style={{ padding: '14px', borderTop: '1px solid #f1f5f9' }}>{order.item_count}</td>
                <td style={{ padding: '14px', borderTop: '1px solid #f1f5f9' }}>${order.total}</td>
                <td style={{ padding: '14px', borderTop: '1px solid #f1f5f9' }}>{order.status}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}"}, {"path": "backend/app.py", "content": "from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/menu')
def get_menu():
    return jsonify({
        'items': [
            {'id': 1, 'name': 'Burger', 'category': 'Fast Food', 'price': 10},
            {'id': 2, 'name': 'Fries', 'category': 'Sides', 'price': 5},
            {'id': 3, 'name': 'Pizza Slice', 'category': 'Fast Food', 'price': 8},
            {'id': 4, 'name': 'Juice', 'category': 'Drinks', 'price': 4}
        ]
    })

@app.route('/api/orders')
def get_orders():
    return jsonify({
        'orders': [
            {'id': 101, 'item_count': 3, 'total_amount': 22, 'status': 'Preparing'},
            {'id': 102, 'item_count': 2, 'total_amount': 14, 'status': 'Delivered'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)"}]}

Prompt:
Build a bookstore e-commerce website with search, category filtering, cart, and customer orders. Use React for frontend and Flask for backend.

TaskSpec:
{
  "app_name": "BookNest E-commerce Website",
  "app_type": "web_app",
  "description": "An online bookstore for searching books, filtering by category, adding books to cart, and managing customer orders.",
  "target_users": [
    "customers",
    "admin"
  ],
  "frontend": {
    "pages": [
      {
        "name": "Home",
        "route": "/",
        "components": [
          "Navbar",
          "HeroSection",
          "FeaturedBooks"
        ]
      },
      {
        "name": "Books",
        "route": "/books",
        "components": [
          "Navbar",
          "SearchBar",
          "CategoryFilter",
          "BookGrid"
        ]
      },
      {
        "name": "Cart",
        "route": "/cart",
        "components": [
          "Navbar",
          "CartList",
          "SummaryCard"
        ]
      },
      {
        "name": "Orders",
        "route": "/orders",
        "components": [
          "Navbar",
          "OrderHistoryTable"
        ]
      }
