      "category filtering",
      "cart management",
      "customer orders"
    ]
  },
  "backend": {
    "endpoints": [
      {
        "method": "GET",
        "path": "/api/books",
        "purpose": "Fetch books"
      },
      {
        "method": "GET",
        "path": "/api/orders",
        "purpose": "Fetch orders"
      }
    ]
  },
  "database": {
    "tables": [
      {
        "name": "books",
        "columns": [
          "id",
          "title",
          "author",
          "category",
          "price"
        ]
      },
      {
        "name": "orders",
        "columns": [
          "id",
          "book_count",
          "total_amount",
          "status"
        ]
      }
    ]
  },
  "auth_required": false
}

